#!/usr/bin/env bash
# Compatibility launcher helper for root-level scripts/* entrypoints.
# Keeps public script paths stable while implementations live in responsibility folders.

exec_script_impl() {
  local script_dir="$1"
  local responsibility_dir="$2"
  local script_name="$3"
  shift 3

  exec "$script_dir/$responsibility_dir/$script_name" "$@"
}

